#pragma OPENCL EXTENSION cl_khr_fp64 : enable

#define BS 16

#define AA(i,j) a[(offset)*size + (i)*size + (j) + (offset)]
#define BB(i,j) a[(i)*size + (j)]

__kernel void lud_diagonal(__global float* a, __local float* shared_mem, int size, int offset)
{
    int i = get_global_id(0);
    if (i >= BS) return;

    int j, k;

    // Process diagonal block
    for (j = i; j < BS; j++) {
        for (k = 0; k < i; k++) {
            AA(i,j) = AA(i,j) - AA(i,k) * AA(k,j);
        }
    }

    float temp = 1.f / AA(i,i);

    for (j = i + 1; j < BS; j++) {
        for (k = 0; k < i; k++) {
            AA(j,i) = AA(j,i) - AA(j,k) * AA(k,i);
        }
        AA(j,i) = AA(j,i) * temp;
    }
}

__kernel void lud_perimeter(__global float* a, __local float* temp, __local float* temp2, int size, int offset)
{
    int gid = get_global_id(0);
    int chunk_idx = gid;

    int size_inter = size - offset - BS;
    int chunks_in_inter_row = size_inter / BS;

    if (chunk_idx >= chunks_in_inter_row) return;

    int i, j, k;
    int i_global = offset;
    int j_global = offset;

    // Load diagonal block into temp
    for (i = 0; i < BS; i++) {
        for (j = 0; j < BS; j++) {
            temp[i*BS + j] = a[size*(i + offset) + offset + j];
        }
    }

    // Update perimeter row blocks
    j_global += BS * (chunk_idx + 1);
    for (j = 0; j < BS; j++) {
        for (i = 0; i < BS; i++) {
            float sum = 0.f;
            for (k = 0; k < i; k++) {
                sum += temp[BS*i + k] * BB(i_global + k, j_global + j);
            }
            BB(i_global + i, j_global + j) = BB(i_global + i, j_global + j) - sum;
        }
    }

    // Update perimeter column blocks
    j_global = offset;
    i_global += BS * (chunk_idx + 1);
    for (i = 0; i < BS; i++) {
        for (j = 0; j < BS; j++) {
            float sum = 0.f;
            for (k = 0; k < j; k++) {
                sum += BB(i_global + i, j_global + k) * temp[BS*k + j];
            }
            a[size*(i_global + i) + j_global + j] = (a[size*(i_global + i) + j_global + j] - sum) / a[size*(offset + j) + offset + j];
        }
    }
}

__kernel void lud_internal(__global float* a, __local float* temp_top, __local float* temp_left, int size, int offset)
{
    int gid_x = get_global_id(0);
    int gid_y = get_global_id(1);

    int size_inter = size - offset - BS;
    int chunks_in_inter_row = size_inter / BS;

    if (gid_x >= chunks_in_inter_row || gid_y >= chunks_in_inter_row) return;

    int i, j, k;
    int i_global = offset + BS * (1 + gid_y);
    int j_global = offset + BS * (1 + gid_x);

    // Load top and left blocks into local memory
    for (i = 0; i < BS; i++) {
        for (j = 0; j < BS; j++) {
            temp_top[i*BS + j] = a[size*(i + offset) + j + j_global];
            temp_left[i*BS + j] = a[size*(i + i_global) + offset + j];
        }
    }

    barrier(CLK_LOCAL_MEM_FENCE);

    float sum[BS];
    for (i = 0; i < BS; i++) {
        for (j = 0; j < BS; j++) {
            sum[j] = 0.f;
        }
        for (k = 0; k < BS; k++) {
            for (j = 0; j < BS; j++) {
                sum[j] += temp_left[BS*i + k] * temp_top[BS*k + j];
            }
        }
        for (j = 0; j < BS; j++) {
            int row = i_global + i;
            int col = j_global + j;
            a[size*row + col] -= sum[j];
        }
    }
}
